-- Additive persistent conversation memory for contextual AI chat.
-- IF NOT EXISTS makes recovery safe if a database stopped partway through this additive migration.
CREATE TABLE IF NOT EXISTS `ai_conversation_contexts` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`conversationId` INTEGER NOT NULL,`userId` INTEGER NOT NULL,`chatId` VARCHAR(191) NOT NULL,`selectedAgentId` INTEGER NULL,`routedAgentId` INTEGER NULL,`currentIntent` VARCHAR(120) NULL,`previousIntent` VARCHAR(120) NULL,`currentModule` VARCHAR(120) NULL,`currentAction` VARCHAR(120) NULL,`currentEntityType` VARCHAR(80) NULL,`currentEntityId` VARCHAR(191) NULL,`selectedCustomerId` VARCHAR(191) NULL,`selectedDeviceId` VARCHAR(191) NULL,`selectedTicketId` VARCHAR(191) NULL,`selectedInvoiceId` VARCHAR(191) NULL,`selectedPaymentId` VARCHAR(191) NULL,`selectedNasId` VARCHAR(191) NULL,`pendingActionId` INTEGER NULL,`pendingApprovalId` INTEGER NULL,`pendingConfirmation` BOOLEAN NOT NULL DEFAULT false,`pendingClarification` JSON NULL,`lastToolCall` JSON NULL,`lastToolResult` JSON NULL,`lastSuccessfulToolResult` JSON NULL,`lastAssistantClaim` JSON NULL,`entityStack` JSON NULL,`conversationSummary` TEXT NULL,`debugTrace` JSON NULL,`expiresAt` DATETIME(3) NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`updatedAt` DATETIME(3) NOT NULL,UNIQUE INDEX `ai_conversation_contexts_conversationId_key`(`conversationId`),INDEX `ai_conversation_contexts_ispId_userId_idx`(`ispId`,`userId`),INDEX `ai_conversation_contexts_chatId_idx`(`chatId`),INDEX `ai_conversation_contexts_selectedCustomerId_idx`(`selectedCustomerId`),INDEX `ai_conversation_contexts_selectedDeviceId_idx`(`selectedDeviceId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS `ai_pending_agent_actions` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`conversationId` INTEGER NOT NULL,`agentId` INTEGER NOT NULL,`requestedBy` INTEGER NOT NULL,`actionType` VARCHAR(120) NOT NULL,`module` VARCHAR(120) NOT NULL,`argumentsEncrypted` JSON NULL,`displayArguments` JSON NULL,`status` VARCHAR(40) NOT NULL DEFAULT 'AWAITING_CONFIRMATION',`requiresApproval` BOOLEAN NOT NULL DEFAULT true,`approvalId` INTEGER NULL,`taskId` INTEGER NULL,`error` TEXT NULL,`expiresAt` DATETIME(3) NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`updatedAt` DATETIME(3) NOT NULL,INDEX `ai_pending_agent_actions_context_status_idx`(`ispId`,`conversationId`,`status`),INDEX `ai_pending_agent_actions_agent_status_idx`(`agentId`,`status`),INDEX `ai_pending_agent_actions_approval_idx`(`approvalId`),INDEX `ai_pending_agent_actions_task_idx`(`taskId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS `ai_agent_routes` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`conversationId` INTEGER NOT NULL,`messageId` INTEGER NULL,`fromAgentId` INTEGER NULL,`toAgentId` INTEGER NOT NULL,`resolvedIntent` VARCHAR(120) NULL,`confidence` DOUBLE NOT NULL DEFAULT 0,`reason` TEXT NULL,`contextSnapshot` JSON NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),INDEX `ai_agent_routes_context_created_idx`(`ispId`,`conversationId`,`createdAt`),INDEX `ai_agent_routes_agent_created_idx`(`toAgentId`,`createdAt`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS `ai_entity_references` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`conversationId` INTEGER NOT NULL,`messageId` INTEGER NULL,`entityType` VARCHAR(80) NOT NULL,`entityId` VARCHAR(160) NOT NULL,`displayLabel` VARCHAR(255) NULL,`source` VARCHAR(40) NOT NULL DEFAULT 'USER',`isActive` BOOLEAN NOT NULL DEFAULT true,`metadata` JSON NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`updatedAt` DATETIME(3) NOT NULL,INDEX `ai_entity_refs_context_type_active_idx`(`ispId`,`conversationId`,`entityType`,`isActive`),INDEX `ai_entity_refs_type_entity_idx`(`entityType`,`entityId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS `ai_conversation_corrections` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`conversationId` INTEGER NOT NULL,`userMessageId` INTEGER NULL,`disputedMessageId` INTEGER NULL,`entityType` VARCHAR(80) NULL,`entityId` VARCHAR(160) NULL,`previousClaim` TEXT NULL,`correctedClaim` TEXT NULL,`verificationResult` JSON NULL,`status` VARCHAR(40) NOT NULL DEFAULT 'RESOLVED',`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),INDEX `ai_corrections_context_created_idx`(`ispId`,`conversationId`,`createdAt`),INDEX `ai_corrections_type_entity_idx`(`entityType`,`entityId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
